class Solution:
    def change(self, amount, coins):
        from functools import lru_cache
        coins = sorted(coins)
        n = len(coins)
        import sys
        sys.setrecursionlimit(100000)
        @lru_cache(maxsize=None)
        def count(i, rem):
            if rem == 0:
                return 1
            if i >= n or rem < 0:
                return 0
            return count(i + 1, rem) + count(i, rem - coins[i])
        result = count(0, amount)
        count.cache_clear()
        return result

